  public static final String GETINVOICEDETAILS = " SELECT INVOICE_SERIAL_NUMBER AS INV_SNO,INVOICE_NUMBER AS INV_NO, INVOICE_FOBAMOUNT AS FOB_AMT,INVOICE_FOBCURRENCY AS FOB_CURR, DECODE(TRIM(FR_EX_AMT),NULL,NVL(INVOICE_FRIEGHTAMOUNT,'0'),FR_EX_AMT) AS FR_AMT, DECODE(TRIM(FR_EX_CURR),NULL,NVL(TRIM(INVOICE_FRIEGHTCURRENCYCODE),INVOICE_FOBCURRENCY),FR_EX_CURR) AS FR_CURR, DECODE(TRIM(INS_EX_AMT),NULL,NVL(INVOICE_INSURANCEAMOUNT,'0'),INS_EX_AMT) AS INS_AMT, DECODE(TRIM(INS_EX_CURR),NULL,NVL(TRIM(INVOICE_INSURANCECURRENCY_CODE),INVOICE_FOBCURRENCY),INS_EX_CURR) AS INS_CURR, DECODE(TRIM(FR_EX_RATE),NULL,(SELECT ETT_BOE_EX_RATE_CAL(NVL(INVOICE_FRIEGHTCURRENCYCODE,INVOICE_FOBCURRENCY),INVOICE_FOBCURRENCY) FROM DUAL),FR_EX_RATE) AS FR_EX_RATE, DECODE(TRIM(INS_EX_RATE),NULL,(SELECT ETT_BOE_EX_RATE_CAL(NVL(INVOICE_INSURANCECURRENCY_CODE,INVOICE_FOBCURRENCY),INVOICE_FOBCURRENCY) FROM DUAL),INS_EX_RATE) AS INS_EX_RATE  FROM ETT_INVOICE_DETAILS WHERE BOE_NUMBER = ? AND TO_CHAR(BOE_DATE,'DD/MM/YYYY') = ? AND BOE_PORT_OF_DISCHARGE = ? AND INVOICE_SERIAL_NUMBER = ? AND TRIM(INVOICE_NUMBER) = ? ";
