  public static final String GET_INV_DETAILS_ON_BOE = "SELECT INV.BOE_NUMBER AS BOE_NUMBER,INV.BOE_DATE AS BOE_DATE,INV.BOE_PORT_OF_DISCHARGE AS BOE_PORT_OF_DISCHARGE,INV.INVOICE_SERIAL_NUMBER AS INV_SERIAL_NO,INV.INVOICE_NUMBER AS INV_NO,INV.INVOICE_TERMS_OF_INVOICE AS INV_TERMS,INV.INVOICE_FOBAMOUNT AS FOB_AMT,INV.INVOICE_FOBCURRENCY AS FOB_CURR,INV.INVOICE_FRIEGHTAMOUNT AS FRI_AMT,INV.INVOICE_FRIEGHTCURRENCYCODE AS FRI_CURR,INV.INVOICE_INSURANCEAMOUNT AS INS_AMT,INV.INVOICE_INSURANCECURRENCY_CODE AS INS_CURR,INV.INVOICE_DISCOUNT_CHARGES AS DISC_CHARGES,INV.INVOICE_DISCOUNT_CURRENCY AS DISC_CURR,INV.INVOICE_AGENCY_COMMISSION AS AGENCY_COMM,INV.INVOICE_AGENCY_CURRENCY AS AGENCY_CURR,INV.INVOICE_MISCELLANEOUS_CHARGES AS MISC_CHARGES,INV.INVOICE_MISCELLANEOUS_CURRENCY AS MISC_CURR,INV.INVOICE_SUPPLIER_NAME AS SUPP_NAME,INV.INVOICE_SUPPLIER_ADDRESS AS SUPP_ADDR,INV.INVOICE_SUPPLIER_COUNTRY AS SUPP_CTY,INV.INVOICE_SELLER_NAME AS SELL_NAME,INV.INVOICE_SELLER_ADDRESS AS SELL_ADDR,INV.INVOICE_SELLER_COUNTRY AS SELL_CTY,INV.INVOICE_THIRDPARTY_NAME AS THIRD_NAME,INV.INVOICE_THIRDPARTY_ADDRESS AS THIRD_ADDR,INV.INVOICE_THIRDPARTY_COUNTRY AS THIRD_CTY,NVL(IPAY.REAL_AMTIC,0) AS REAL_AMTIC,NVL(BCL.CLOSURE_AMTIC,0) AS  CLOSURE_AMTIC FROM ETT_INVOICE_DETAILS INV,(SELECT INV_SNO,INV_NO,BOE_NO,BOE_DATE,PORTCODE,SUM(REAL_ORM_AMT) AS REAL_AMTIC FROM ETT_BOE_INV_PAYMENT GROUP BY INV_SNO,INV_NO,BOE_NO,BOE_DATE,PORTCODE) IPAY,(SELECT INV_SNO,INV_NO,BOE_NO,BOE_DATE,PORTCODE,SUM(ADJ_INVAMT) AS CLOSURE_AMTIC FROM ETT_BOE_INV_CLOSURE WHERE STATUS != 'R' GROUP BY INV_SNO,INV_NO,BOE_NO,BOE_DATE,PORTCODE) BCL WHERE INV.INVOICE_SERIAL_NUMBER        = IPAY.INV_SNO  (+) AND INV.INVOICE_NUMBER                 = IPAY.INV_NO   (+) AND INV.BOE_NUMBER                     = IPAY.BOE_NO   (+) AND INV.BOE_DATE                       = IPAY.BOE_DATE (+) AND INV.BOE_PORT_OF_DISCHARGE          = IPAY.PORTCODE (+) AND INV.INVOICE_SERIAL_NUMBER          = BCL.INV_SNO   (+) AND INV.INVOICE_NUMBER                 = BCL.INV_NO    (+) AND INV.BOE_NUMBER                     = BCL.BOE_NO    (+) AND INV.BOE_DATE                       = BCL.BOE_DATE  (+) AND INV.BOE_PORT_OF_DISCHARGE          = BCL.PORTCODE  (+) AND INV.BOE_NUMBER = ? AND TO_CHAR(INV.BOE_DATE,'DD/MM/YYYY') = ? AND INV.BOE_PORT_OF_DISCHARGE = ? ORDER BY INV.INVOICE_SERIAL_NUMBER  ";
  public static final String FETCH_PAY_DETAILS = " SELECT TRIM(BOE_PAYMENT_BP_BOE_NO) AS BILLOFENTRYNUMBER,TO_CHAR(BOE_PAYMENT_BP_BOE_DT,'DD/MM/YYYY') AS BILLOFENTRYDATE,TRIM(PORT_CODE) AS PORTOFDISCHARGE,TRIM(BOE_ENTRY_AMT) AS BOE_ENTRY_AMT,TRIM(BOE_PAYMENT_BP_BOE_CCY) AS BOE_ENTRY_CURR,TRIM(BOE_PAYMENT_CIF_NAME) AS CUSTOMER_NAME,TRIM(BOE_PAYMENT_BENEF_NAME) AS BENEF_NAME,TRIM(BOE_PAYMENT_BENEF_COUNTRY) AS BENEF_CTY,TRIM(BOE_PAYMENT_BP_PAY_REF) AS MASTER_REFNO,TRIM(BOE_PAYMENT_BP_PAY_PART_REF) AS EVENTREFNO,TRIM(BOE_PAYMENT_BP_PAY_CCY) AS REMITTANCECURRENCY,TRIM(BOE_PAYMENT_BP_PAY_FC_AMT) AS BILL_AMT,NVL(TRIM(BOE_PAYMENT_BP_PAY_ENDORSE_AMT),0) AS REAL_AMT,NVL(TRIM(ENDORSED_BOE_AMT),0) AS REAL_ORM_AMT FROM ETT_BOE_PAYMENT WHERE BOE_PAYMENT_BP_PAY_REF=BOE_PAYMENT_BP_PAY_REF";
